#!/usr/bin/env python3
"""Combine all LG manual topic HTML files into one big scrollable page."""

import os
import re
from pathlib import Path

BASE = Path(__file__).parent
TOPICS_DIR = BASE / "topics"
RES_DIR = BASE / "res"

# Read indexer.js to get the ordering
with open(TOPICS_DIR / "js" / "indexer.js", "r") as f:
    indexer_content = f.read()

# Parse urlHash, title, contents arrays from indexer.js
url_hash_entries = re.findall(r"urlHash\[(\d+)\]='([^']*)'", indexer_content)
title_entries = re.findall(r"title\[(\d+)\]='([^']*)'", indexer_content)
contents_entries = re.findall(r"contents\[(\d+)\]='([^']*)'", indexer_content)

# Build ordered list from indexer (lowest index first)
all_ids = sorted(set(int(k) for k, _ in url_hash_entries))

ordered = []
for idx in all_ids:
    topic_id = dict(url_hash_entries).get(str(idx), "")
    title_text = dict(title_entries).get(str(idx), "")
    ordered.append((idx, topic_id, title_text))

# Read the CSS from the LGE CDN (we'll inline what we need)
# For a self-contained page, let's use a clean embedded stylesheet
CSS = """
/* Reset & base */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

body {
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    line-height: 1.6;
    color: #333;
    background: #f5f5f5;
}

.manual-page {
    max-width: 900px;
    margin: 0 auto;
    background: #fff;
    padding: 40px 48px;
}

/* Sticky TOC */
.toc-bar {
    position: sticky;
    top: 0;
    z-index: 100;
    background: #fff;
    border-bottom: 2px solid #e0e0e0;
    padding: 12px 0;
    margin-bottom: 32px;
}

.toc-bar h2 {
    font-size: 1.1rem;
    color: #666;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    margin-bottom: 8px;
}

.toc-links {
    display: flex;
    flex-wrap: wrap;
    gap: 6px 14px;
}

.toc-links a {
    color: #1a73e8;
    text-decoration: none;
    font-size: 0.9rem;
    padding: 2px 6px;
    border-radius: 4px;
    transition: background 0.15s;
}

.toc-links a:hover {
    background: #e8f0fe;
    text-decoration: underline;
}

/* Section headers */
.manual-page h1 {
    font-size: 1.8rem;
    color: #1a1a1a;
    border-bottom: 3px solid #1a73e8;
    padding-bottom: 8px;
    margin: 48px 0 24px 0;
}

.manual-page h2 {
    font-size: 1.3rem;
    color: #222;
    margin: 32px 0 16px 0;
    padding-top: 12px;
}

.manual-page h3, .manual-page h4 {
    font-size: 1.1rem;
    color: #333;
    margin: 20px 0 10px 0;
}

/* Tables */
.manual-page table {
    width: 100%;
    border-collapse: collapse;
    margin: 16px 0;
    font-size: 0.95rem;
}

.manual-page table th,
.manual-page table td {
    border: 1px solid #ccc;
    padding: 10px 12px;
    vertical-align: top;
}

.manual-page table th {
    background: #f0f4f8;
    font-weight: 600;
}

/* Images */
.manual-page img {
    max-width: 100%;
    height: auto;
    display: block;
    margin: 12px auto;
    border: 1px solid #ddd;
    border-radius: 4px;
}

/* Paragraphs */
.manual-page p, .manual-page .p {
    margin: 8px 0;
}

/* Bold / emphasis */
.manual-page b, .manual-page strong {
    font-weight: 700;
}

.manual-page .emphasis {
    font-style: italic;
}

.manual-page .bold {
    font-weight: 700;
}

/* Summary boxes */
.summary {
    background: #f8f9fa;
    border-left: 4px solid #1a73e8;
    padding: 12px 16px;
    margin: 16px 0;
    font-size: 0.95rem;
}

/* Contained topics lists */
.containd-topics, .containd-section {
    background: #fffbe6;
    border: 1px solid #ffe58f;
    padding: 12px 16px;
    margin: 16px 0;
    border-radius: 4px;
}

.containd-topics dt, .containd-section dt {
    font-weight: 700;
    margin-bottom: 4px;
}

.containd-topics dd, .containd-section dd {
    margin-left: 16px;
    margin-bottom: 2px;
}

.containd-topics a, .containd-section a {
    color: #1a73e8;
    text-decoration: none;
}

.containd-topics a:hover, .containd-section a:hover {
    text-decoration: underline;
}

/* Breadcrumbs */
.bread-clumb {
    font-size: 0.8rem;
    color: #888;
    margin-bottom: 16px;
}

.bread-clumb a {
    color: #1a73e8;
    text-decoration: none;
}

/* Top page / title page */
.top-header {
    text-align: center;
    padding: 40px 20px;
    border-bottom: 2px solid #e0e0e0;
    margin-bottom: 32px;
}

.top-header h1 {
    font-size: 2.2rem;
    border: none;
    margin-bottom: 8px;
}

.top-header p {
    font-size: 1.1rem;
    color: #666;
}

/* Section nav grid */
.section-nav-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
    gap: 12px;
    margin: 24px 0;
}

.section-nav-grid a {
    display: block;
    padding: 16px;
    background: #f0f4f8;
    border-radius: 8px;
    text-decoration: none;
    color: #1a73e8;
    font-weight: 600;
    text-align: center;
    transition: background 0.15s;
}

.section-nav-grid a:hover {
    background: #d2e3fc;
}

/* Scroll to top */
.scroll-top-btn {
    position: fixed;
    bottom: 24px;
    right: 24px;
    width: 48px;
    height: 48px;
    border-radius: 50%;
    background: #1a73e8;
    color: #fff;
    display: flex;
    align-items: center;
    justify-content: center;
    text-decoration: none;
    font-size: 1.5rem;
    box-shadow: 0 2px 8px rgba(0,0,0,0.2);
    opacity: 0;
    transition: opacity 0.3s;
    z-index: 200;
}

.scroll-top-btn.visible {
    opacity: 1;
}

/* Print styles */
@media print {
    .toc-bar, .scroll-top-btn { display: none !important; }
    .manual-page { padding: 0; max-width: none; }
    body { background: #fff; }
}

/* Responsive */
@media (max-width: 600px) {
    .manual-page { padding: 20px 16px; }
}
"""


def read_html_file(path):
    """Read an HTML file and return its content."""
    with open(path, "r", encoding="utf-8") as f:
        return f.read()


def clean_topic_html(html_str):
    """Extract the meaningful content from a topic HTML file, stripping navigation junk."""
    # Remove swiper-slide wrappers (empty slides)
    html_str = re.sub(r'<div class="swiper-slide"></div>', '', html_str)

    # Remove swiper navigation buttons and pagination
    html_str = re.sub(r'<div class="swiper-button-prev"></div>', '', html_str)
    html_str = re.sub(r'<div class="swiper-button-next"></div>', '', html_str)
    html_str = re.sub(r'<div class="pagination">.*?</div>', '', html_str, flags=re.DOTALL)

    # Remove swiper scripts
    html_str = re.sub(r'<script>\s*\n?\s*$(function\(\)\{[\s\S]*?});\s*\n\s*</script>', '', html_str)

    return html_str


def is_topic_file(filename):
    """Check if a filename represents actual content (not just navigation)."""
    return filename.startswith("topic_")


def is_section_file(filename):
    return filename.startswith("section_")


def is_chapter_file(filename):
    return filename.startswith("chapter_")


def is_preface_file(filename):
    return filename.startswith("preface_")


def main():
    # Collect all content files in order based on indexer
    file_map = {}  # topic_id -> html_content
    for fname in os.listdir(TOPICS_DIR):
        if not fname.endswith(".html"):
            continue
        fpath = TOPICS_DIR / fname
        html = read_html_file(fpath)
        file_map[fname.replace(".html", "")] = html

    # Build the page
    parts = []

    # --- Title page ---
    top_html = clean_topic_html(file_map.get("top", ""))
    parts.append(f"""
    <div class="topic-inner top-page">
        {top_html}
    </div>
""")

    # --- Build TOC ---
    toc_sections = []
    for idx, topic_id, title_text in ordered:
        if not topic_id or topic_id == "top":
            continue
        # Clean up title
        clean_title = title_text.strip()
        if not clean_title:
            continue
        toc_sections.append((topic_id, clean_title))

    toc_html = '<div class="toc-bar"><h2>Table of Contents</h2><div class="toc-links">'
    for topic_id, title in toc_sections:
        anchor = topic_id.replace("_", "-")
        toc_html += f'<a href="#{anchor}">{title}</a>'
    toc_html += '</div></div>'

    parts.append(toc_html)

    # --- Now output all content in order ---
    for idx, topic_id, title_text in ordered:
        if not topic_id or topic_id == "top":
            continue

        html = file_map.get(topic_id, "")
        if not html:
            continue

        clean_html = clean_topic_html(html)

        # Add anchor and heading
        anchor = topic_id.replace("_", "-")

        # Check if this is a section/chapter that has navigation links inside
        # We want to show the content but keep internal links working
        parts.append(f"""
    <div id="{anchor}" class="manual-section">
        {clean_html}
    </div>
""")

    # --- Scroll to top button ---
    parts.append("""
    <a href="#" class="scroll-top-btn" id="scrollTopBtn" title="Back to top">↑</a>
""")

    # --- JS for scroll-to-top ---
    js = """
    <script>
        // Show/hide scroll-to-top button
        const btn = document.getElementById('scrollTopBtn');
        window.addEventListener('scroll', () => {
            if (window.scrollY > 400) {
