}
"""


def read_html_file(path):
    with open(path, "r", encoding="utf-8") as f:
        return f.read()


def clean_topic_html(html_str):
    """Extract meaningful content, stripping swiper navigation junk."""
    # Remove empty swiper slides
    html_str = re.sub(r'<div class="swiper-slide"></div>', '', html_str)

    # Remove swiper navigation buttons and pagination
    html_str = re.sub(r'<div class="swiper-button-prev"></div>', '', html_str)
    html_str = re.sub(r'<div class="swiper-button-next"></div>', '', html_str)
    html_str = re.sub(r'<div class="pagination">.*?</div>', '', html_str, flags=re.DOTALL)

    # Remove ALL swiper-related scripts (be aggressive - these are navigation-only)
    html_str = re.sub(
        r'<script>[\s\S]*?new Swiper[\s\S]*?</script>',
        '',
        html_str,
    )

    return html_str


# Map chapter/section/prep files to their display titles (from main.html nav)
CHAPTER_TITLES = {
    "preface_1": "IMPORTANT SAFETY INSTRUCTIONS",
    "chapter_1": "INSTALLATION",
    "chapter_2": "OPERATION",
    "chapter_3": "SMART FUNCTIONS",
    "chapter_4": "MAINTENANCE",
    "appendix_1": "TROUBLESHOOTING",
    "appendix_2": "LIMITED WARRANTY",
}


def main():
    # Read indexer.js to get ordering
    with open(BASE / "res" / "js" / "indexer.js", "r") as f:
        indexer_content = f.read()

    url_hash_entries = re.findall(
        r"urlHash\[(\d+)\]='([^']*)'", indexer_content
    )
    title_entries = re.findall(
        r"title\[(\d+)\]='([^']*)'", indexer_content
    )

    all_ids = sorted(set(int(k) for k, _ in url_hash_entries))

    ordered = []
    for idx in all_ids:
        topic_id = dict(url_hash_entries).get(str(idx), "")
        title_text = dict(title_entries).get(str(idx), "")
        ordered.append((idx, topic_id, title_text))

    # Read all HTML files
    file_map = {}
    for fname in os.listdir(TOPICS_DIR):
        if not fname.endswith(".html"):
            continue
        fpath = TOPICS_DIR / fname
        html = read_html_file(fpath)
        file_map[fname.replace(".html", "")] = html

    # Build page parts
    parts = []

    # Title page
    top_html = clean_topic_html(file_map.get("top", ""))
    parts.append('<div class="topic-inner top-page">' + top_html + '</div>')

    # Build TOC - include chapter-level items not in indexer
    toc_sections = []
    seen_ids = set()

    for idx, topic_id, title_text in ordered:
        if not topic_id or topic_id == "top":
            continue
        clean_title = title_text.strip()
        if not clean_title:
            continue
        toc_sections.append((topic_id, clean_title))
        seen_ids.add(topic_id)

    # Add chapter/appendix headers that are missing from indexer
    for name, display_name in CHAPTER_TITLES.items():
        if name not in seen_ids and file_map.get(name):
            toc_sections.append((name, display_name))

    # Build TOC HTML
    toc_links_html = ""
    for topic_id, title in toc_sections:
        anchor = topic_id.replace("_", "-")
        toc_links_html += '<a href="#' + anchor + '">' + title + '</a>'

    parts.append(
        '<div class="toc-bar">'
        '<h2>Table of Contents</h2>'
        '<div class="toc-links">'
        + toc_links_html
        + '</div></div>'
    )

    # All content sections in order (from indexer)
    for idx, topic_id, title_text in ordered:
        if not topic_id or topic_id == "top":
            continue

        html = file_map.get(topic_id, "")
        if not html:
            continue

        clean_html = clean_topic_html(html)
        anchor = topic_id.replace("_", "-")

        parts.append(
            '<div id="' + anchor + '" class="manual-section">'
            + clean_html
            + '</div>'
        )

    # Add chapter/appendix/preface files that weren't in the indexer
    for name, display_name in CHAPTER_TITLES.items():
        if name not in seen_ids and file_map.get(name):
            html = file_map[name]
            clean_html = clean_topic_html(html)
            anchor = name.replace("_", "-")
            parts.append(
                '<div id="' + anchor + '" class="manual-section">'
                + clean_html
                + '</div>'
            )

    # Scroll-to-top button
    parts.append('<a href="#" class="scroll-top-btn" id="scrollTopBtn" title="Back to top">&#8593;</a>')

    # Assemble full HTML
    js = """<script>
        var btn = document.getElementById('scrollTopBtn');
        window.addEventListener('scroll', function() {
            if (window.scrollY > 400) {
                btn.classList.add('visible');
            } else {
                btn.classList.remove('visible');
            }
        });

        document.querySelectorAll('.toc-links a').forEach(function(a) {
            a.addEventListener('click', function(e) {
                e.preventDefault();
                var target = document.querySelector(a.getAttribute('href'));
                if (target) {
                    target.scrollIntoView({ behavior: 'smooth', block: 'start' });
                }
            });
        });

        document.querySelectorAll('.manual-section a[href^="#"]').forEach(function(a) {
            a.addEventListener('click', function(e) {
                e.preventDefault();
                var target = document.querySelector(a.getAttribute('href'));
                if (target) {
                    target.scrollIntoView({ behavior: 'smooth', block: 'start' });
                }
            });
        });
    </script>"""

    full_html = """<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>LG Air Conditioner Owner's Manual - LW1224RD, LW1424RD</title>
    <style>""" + CSS + """</style>
</head>
<body>
<div class="manual-page">
""" + "\n".join(parts) + """
</div>
""" + js + """
</body>
</html>"""

    output_path = BASE / "single.html"
    with open(output_path, "w", encoding="utf-8") as f:
        f.write(full_html)

    print("Wrote " + str(output_path))
    print("Total sections in TOC: " + str(len(toc_sections)))


if __name__ == "__main__":
    main()
